VALUES
  ('land-agent-moex-00186', 'land-agent', 'land-agent-moex-106-1ee8220b', 'sub-land-agent-04', NULL, 'essay', '甲、乙為夫妻，育有子女丙、丁，戊為甲之父。甲於婚前之銀行存款已有 300 萬元，
乙於婚前則無財產，然甲於婚後因經商有成，於死亡前銀行存款已有 1000萬元，乙
婚後負責打理居家生活並照顧丙、丁而無收入，請問：何人有繼承權？（12 分）
應繼分比例各為若干？（13分）
（請接背面）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "9016e48bb607", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "201", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要與信託法概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": "四", "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00187', 'land-agent', 'land-agent-moex-105-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '由上文敘述，可知進言最難的是：', '["背景知識不足", "表達能力不佳", "了解對方心理", "不敢暢所欲言"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "c93f2befde9f", "answer_pdf_sha1": "6aa8da7d1cdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00188', 'land-agent', 'land-agent-moex-105-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '依上文，最不容易進言的國君是那一類：', '["為名高者", "為厚利者", "表面求名高，實際愛厚利者", "表面求厚利，實際求名高者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "c93f2befde9f", "answer_pdf_sha1": "6aa8da7d1cdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00189', 'land-agent', 'land-agent-moex-105-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '楊子之鄰人亡羊，既率其黨，又請楊子之豎追之。楊子曰：「嘻！亡一羊，何追者 之眾？」鄰人曰：「多歧路」既反，問：「獲羊乎？」曰：「亡之矣。」曰：「奚 亡之？」曰：「歧路之中又有歧焉，吾不知所之，所以反也。」楊子戚然變容，不 言者移時，不笑者竟日。門人怪之，請曰：「羊，賤畜；又非夫子之有，而損言笑 者，何哉？」楊子不答，門人不獲所命。弟子孟孫陽出，以告心都子……心都子曰： 「大道以多歧亡羊，學者以多方喪生。」 「歧路亡羊」的故事意指為學須：', '["廣博", "立志", "有恆", "專一"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "c93f2befde9f", "answer_pdf_sha1": "6aa8da7d1cdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00190', 'land-agent', 'land-agent-moex-105-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '黃庭堅〈書嵇叔夜詩與姪榎〉：「或問不俗之狀。余曰：難言也。視其平居無以異 於俗人，臨大節而不可奪，此不俗人也。」 從上文推知，黃庭堅所謂「不俗」之人，乃著眼於那一方面？', '["生活品味", "談吐學問", "胸襟氣度", "道德操守"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "c93f2befde9f", "answer_pdf_sha1": "6aa8da7d1cdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00191', 'land-agent', 'land-agent-moex-105-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '申子言：「治不踰官，雖知弗言。」（《韓非子．定法》） 其意與下列何者相同？', '["不在其位，不謀其政", "居之無倦，行之以忠", "先有司，赦小過，舉賢才", "舉直錯諸枉，則民服；舉枉錯諸直，則民不服"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "c93f2befde9f", "answer_pdf_sha1": "6aa8da7d1cdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00192', 'land-agent', 'land-agent-moex-105-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '徐幹：「人君明乎賞罰之道，則治不難矣。夫賞罰者，不在乎必重，而在於必行。 必行，則雖不重，而民肅；不行，則雖重，而民怠。故先王務賞罰之必行。」（《中 論．賞罰》） 根據本文，作者強調的賞罰之道是：', '["罪疑惟輕，使民改過", "貫徹法令，取信於民", "寬嚴並濟，以獲民心", "嚴刑峻罰，以正視聽"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "c93f2befde9f", "answer_pdf_sha1": "6aa8da7d1cdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00193', 'land-agent', 'land-agent-moex-105-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '「子謂仲弓曰：『犁牛之子騂且角，雖欲勿用，山川其舍諸？』」（《論語．雍也》） 這段話與下列那一選項的精神最接近？', '["將相本無種，男兒當自強（高明《琵琶記》）", "不畏浮雲遮望眼，自緣身在最高層（王安石〈登飛來峰〉）", "山重水複疑無路，柳暗花明又一村（陸游〈遊山西村〉）", "千淘萬漉雖辛苦，吹盡狂沙始到金（劉禹錫〈浪淘沙〉其八）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "c93f2befde9f", "answer_pdf_sha1": "6aa8da7d1cdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00194', 'land-agent', 'land-agent-moex-105-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '文君夜亡奔相如，相如乃與馳歸成都。家居徒四壁立。卓王孫大怒曰：「女至不材， 我不忍殺，不分一錢也。」人或謂王孫，王孫終不聽。文君久之不樂，曰：「長卿 第俱如臨邛，從昆弟假貸猶足為生，何至自苦如此！」相如與俱之臨邛，盡賣其車 騎，買一酒舍酤酒，而令文君當鑪。相如身自著犢鼻褌，與保庸雜作，滌器於市中。 卓王孫聞而恥之，為杜門不出。昆弟諸公更謂王孫曰：「有一男兩女，所不足者非 財也。今文君已失身於司馬長卿，長卿故倦遊，雖貧，其人材足依也，且又令客， 獨奈何相辱如此！」卓王孫不得已，分予文君僮百人，錢百萬，及其嫁時衣被財物。 文君乃與相如歸成都，買田宅，為富人。（《史記‧司馬相如列傳》） 依據上文，下列敘述何者錯誤？', '["本段文字常被視為才子佳人小說之濫觴", "最初卓王孫氣女兒沒出息，不願分給她一分錢", "卓王孫最後仍給女兒財產，關鍵是兄弟諸公的勸說", "卓文君夜奔司馬相如，發現他家徒四壁，後悔跟了他"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "c93f2befde9f", "answer_pdf_sha1": "6aa8da7d1cdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00195', 'land-agent', 'land-agent-moex-105-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '陳克華《無醫村手記‧告別秀姑巒溪》描述其服役期間擔任軍醫，在花、東交界的 「靜埔醫務所」面對村民看診的經驗，指出：白天七點不到便有門診病人上門。通 常是他們的吐痰及咳嗽聲叫我起床。候診室裏人聲沸騰。「先生啊，我想要打針， 打針好得比較快」、「我有發燒，我都是『燒腹內』的」、「先生啊，照上次給我 的那種一排二十四顆的藥就可以了」、「這種病是不是不能吃木瓜、鴨肉」、「被 刀子割到我就用香煙嚼一嚼蓋上去就好了」、「我吃中藥吃了兩千塊，腿不痠了， 却腫得有兩根粗」、「開一點青黴素給我好了，我的腿痛一定要吃青黴素」、「大 夫，我的糖尿病就是吃這種五葉靈芝吃好的吔」、「大夫，我來打點滴」 這顯示他這段行醫經驗，最大的困擾是：', '["當地生病的人太多，可是人手不足，讓他應接不暇", "病人有許多根深柢固、自以為是、牢不可破的錯誤觀念", "許多病人衛生習慣不好，例如吐痰，就造成更多的疾病傳染", "病人的狀況千奇百怪，讓這位年輕、沒有太多經驗的醫生飽受壓力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "c93f2befde9f", "answer_pdf_sha1": "6aa8da7d1cdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL)
